+export function createSystemPromptAppender(
+  appendPrompt: string,
+): (defaultPrompt: string) => string {
+  const trimmed = appendPrompt.trim();
+  if (!trimmed) {
+    return (defaultPrompt) => defaultPrompt;
+  }
+  return (defaultPrompt) => `${defaultPrompt}\n\n${appendPrompt}`;
+}
